```python

import traitlets as T

class DiTToTraitType(T.TraitType):

    def get(self, obj, cls=None):

        r = obj.notify_change(T.Bunch(
            name=self.name,
            value=obj._trait_values[self.name],
            owner=self,
            type='fetch',
        ))

        if r is not None and r != obj._trait_values[self.name]:
            warnings.warn("Response from callback event 'fetch' on property {} does not match previous value. Overloading existing value {} with new value {}".format(
                self.name,
                obj._trait_values[self.name],
                r
                ))
            obj._trait_values[self.name] = r

        return super().get(obj, cls=cls)

class Float(T.Float, DiTToTraitType):
    pass

```

