I'm going to hold off on adding this feature.

You should, however, be able to implement this functionality in your own schemas like so:

```python
from marshmallow import Schema, fields

class Model(object):
    def __init__(self, **kwargs):
        self.__dict__.update(kwargs)

class BaseSchema(Schema):
    
    def __init__(self, *args, **kwargs):
        self.include = kwargs.pop('include', None)
        super().__init__(*args, **kwargs)
        
    def _update_fields(self, *args, **kwargs):
        super()._update_fields(*args, **kwargs)
        if self.include:
            for field_name in self.include:
                self.fields[field_name] = self._declared_fields[field_name]

        
class Member(BaseSchema):
    id = fields.Integer()
    email = fields.Email()
    firstname = fields.String()
    lastname = fields.String()
    photo = fields.Raw()
    
    class Meta:
        exclude = ('photo',)
        
member = Model(id=42, email='mick@stones.com', firstname='Mick', lastname='Jagger', photo='1010')

Member().dump(member).data
# {'email': 'mick@stones.com',
#  'firstname': 'Mick',
#  'id': 42,
#  'lastname': 'Jagger'}

Member(include=('photo', )).dump(member).data
# {'email': 'mick@stones.com',
#  'firstname': 'Mick',
#  'id': 42,
#  'lastname': 'Jagger',
#  'photo': '1010'}

@morgan If you're using a framework with a thread-local request object, you could do something like:

```python
from flask import request
from marshmallow import missing, Schema, fields, ValidationError

def required_on_post(val):
    if request.method == 'POST':
        if val is missing:
            raise ValidationError('Field is required')
        
class UserSchema(Schema):
    password = fields.Str(validate=required_on_post, load_only=True)
```

Of course, this can be generalized with a validator class like `RequiredForMethods`.

